# Preprocessing functions
def preprocess(text):
    # Tokenization
    tokens = text.split()
    # Remove stop words (example list)
    stop_words = {'the', 'and', 'of', 'to', 'a', 'in', 'is', 'it', 'that', 'this', 'are', 'be', 'on', 'for'}
    tokens = [word.lower() for word in tokens if word.lower() not in stop_words]
    # Stemming (simple example)
    stems = [word for word in tokens]
    return stems

# Training function
def train_naive_bayes(corpus, labels):
    class_counts = defaultdict(int)
    word_class_counts = defaultdict(lambda: defaultdict(int))
    total_words = 0

    for label, text in zip(labels, corpus):
        class_counts[label] += 1
        words = preprocess(text)
        for word in words:
            word_class_counts[label][word] += 1
            total_words += 1

    # Calculate probabilities
    class_probabilities = {label: math.log(count / len(corpus)) for label, count in class_counts.items()}
    word_probabilities = {}

    for label in class_counts:
        word_probabilities[label] = {}
